import{_ as t,o as d,c as a,a as r}from"./app-f4076533.js";const e={},h=r('<h1 id="周报" tabindex="-1"><a class="header-anchor" href="#周报" aria-hidden="true">#</a> 周报</h1><h2 id="本周总结" tabindex="-1"><a class="header-anchor" href="#本周总结" aria-hidden="true">#</a> 本周总结：</h2><p>云南用途管制 1、用途管制智能体: 1）。 2）。 3）。 4）。 2、查询优化 1） 3、其他系统优化功能： 1）报盘导入优化界址点部分内容，从数据包保存修改为原生JDBC批量插入，对于一万个界址点的项目导入，从50s优化到6s。6 2）fix: 更新后，通过按钮手动打开的表单无法切换问题处理。</p><p>拉萨一体化： 1、。</p><p>下周计划： 云南用途管制： 1、矿压业务相关内容完善优化。 2、系统优化剩余的查询相关功能优化。 3、智能体按照原型图，对前端页面进行改造。 4、其他运维。</p><p>拉萨一体化： 1、系统开发运维支持。</p><h1 id="年终总结大纲" tabindex="-1"><a class="header-anchor" href="#年终总结大纲" aria-hidden="true">#</a> 年终总结大纲</h1><h2 id="个人总结" tabindex="-1"><a class="header-anchor" href="#个人总结" aria-hidden="true">#</a> 个人总结</h2><h3 id="_1、工作成果" tabindex="-1"><a class="header-anchor" href="#_1、工作成果" aria-hidden="true">#</a> 1、工作成果</h3><h4 id="_1-1-项目投入成果" tabindex="-1"><a class="header-anchor" href="#_1-1-项目投入成果" aria-hidden="true">#</a> 1.1 项目投入成果</h4><h4 id="_1-2-云南用途管制-等保改造成果" tabindex="-1"><a class="header-anchor" href="#_1-2-云南用途管制-等保改造成果" aria-hidden="true">#</a> 1.2 云南用途管制-等保改造成果</h4><p>对系统进行了完整的密码改造，包括密码传输加密，数据库加密，数据完整性签名，双因子认证，以及服务器安全改造等内容。</p><h4 id="_1-3-云南用途管制-全面优化成果" tabindex="-1"><a class="header-anchor" href="#_1-3-云南用途管制-全面优化成果" aria-hidden="true">#</a> 1.3 云南用途管制-全面优化成果</h4><p>通过从前端，到后端，再到查询，以至服务器部署架构全面改造，对系统进行完整优化。</p><h4 id="_1-4-云南用途管制-一体化平台迁移改造成果" tabindex="-1"><a class="header-anchor" href="#_1-4-云南用途管制-一体化平台迁移改造成果" aria-hidden="true">#</a> 1.4 云南用途管制-一体化平台迁移改造成果</h4><p>为保障项目长远运行发展，项目产品团队支援云南，对一体化平台的迁移应用升级，目前已经打通了整体的工作流，采用最新的产品以及更新的应用构建方式，为用途管制升级做好前置准备。</p><h4 id="_1-5-拉萨一体化-应用支援成果" tabindex="-1"><a class="header-anchor" href="#_1-5-拉萨一体化-应用支援成果" aria-hidden="true">#</a> 1.5 拉萨一体化-应用支援成果</h4><p>在上线前的关键时期，作为主力支持拉萨项目开发3-4个月，直至推至系统上线。期间除了处理上线初期系统大量存在的细节问题外，还支持了核心的流程业务开发，地方特色的会审业务实现，在线拟文，外部对接，批后监管等模块的开发。同时也给不熟悉数慧产品的交付人员讲解了产品的基本使用，以及流程建模的基础知识内容，后逐渐进行远程支持。</p><h3 id="_2、个人收获" tabindex="-1"><a class="header-anchor" href="#_2、个人收获" aria-hidden="true">#</a> 2、个人收获</h3><ul><li>新架构的产品使用和基于产品的开发能力。</li><li>应用优化能力。</li><li>AI模型使用能力。</li></ul><h3 id="_3、-不足与展望" tabindex="-1"><a class="header-anchor" href="#_3、-不足与展望" aria-hidden="true">#</a> 3、 不足与展望</h3><h4 id="_3-1-不足" tabindex="-1"><a class="header-anchor" href="#_3-1-不足" aria-hidden="true">#</a> 3.1 不足</h4><p>1、任务管理：工作分配不明确，导致工作干的杂，一些时间用在运维上。<br> 2、项目管理：组织能力欠佳，有时无法和交付人员合理的分配工作和交流。<br> 3、技术深度：部分技术内容深度还是不够，很多业务需求的实现不够优雅。</p><h4 id="_3-2-展望" tabindex="-1"><a class="header-anchor" href="#_3-2-展望" aria-hidden="true">#</a> 3.2 展望</h4><p>1、技术深度，在流程引擎方面继续深入，成为懂流程，会设计流程的团队成员。 2、项目管理：提高项目管理要求，严格把控代码规范质量，致力于项目代码方面高质量。 3、自动化测试能力提升，现阶段任务开发完毕后，绝大部分是由人工测试，准确度和精细度不高。 4、团队提升：开展一些项目内部的培训，如如何精准的定位问题，更完整的进行系统测试，查看功能接口用时，服务器监控以及日志基本查看等技术，打造优秀团队。</p><h3 id="_4、对组织的期望或建议" tabindex="-1"><a class="header-anchor" href="#_4、对组织的期望或建议" aria-hidden="true">#</a> 4、对组织的期望或建议</h3><p>1、团队内部交流欠缺，目前还停留在单纯的工作和事项交汇中，推荐增加团队内部支持，心得交流等活动。<br> 2、优化项目管理模式，现有模式下是依靠每周任务。<br> 3、新产品培训，内部产品培训停留在表面。例如数慧产品的已存在系列视频，但是真正项目开发中，实施人员遇到的问题很多，一部分是在培训中提及不足，一部分是学习人员未能理解。系列教程需要优化完善。</p><h3 id="工作总览" tabindex="-1"><a class="header-anchor" href="#工作总览" aria-hidden="true">#</a> 工作总览</h3><table><thead><tr><th>月份</th><th>云南用途管制</th><th>拉萨一体化</th><th>黔西南工建</th></tr></thead><tbody><tr><td>1</td><td>云南用途管制功能升级和维护</td><td></td><td></td></tr><tr><td>2</td><td>云南用途管制功能升级和维护</td><td></td><td>黔西南工建运维</td></tr><tr><td>3</td><td>云南用途管制功能升级和维护</td><td></td><td>黔西南工建运维</td></tr><tr><td>4</td><td>云南用途管制功能升级和维护、一体化4A平台对接、密码改造</td><td></td><td>黔西南工建运维</td></tr><tr><td>5</td><td>云南用途管制功能升级和维护（电子报盘新业务）、等保测评</td><td>拉萨一体化(前期推进，应用上线bug、流程、构建中心的使用)</td><td>黔西南工建运维</td></tr><tr><td>6</td><td>安全等级保护评测、电子报盘专章业务。计划管理新内容推进。</td><td>拉萨一体化(前期推进，应用上线bug、流程、构建中心的使用、批后监管)</td><td></td></tr><tr><td>7</td><td>用途管制查询优化、服务器架构调整，服务器相关安全等保改造。</td><td>拉萨一体化（会审流程、权限控制问题，NTKO拟文，表单打印，批后监管模块相关内容）</td><td></td></tr><tr><td>8</td><td>统一对接应用开发、指标管理完善</td><td>拉萨一体化（对接）</td><td></td></tr><tr><td>9</td><td>指标管控模块。一体化迁移</td><td>数据治理模块，自定义会审表单绘制，图片预览服务部署。应用上线，交接主要工作内容</td><td></td></tr><tr><td>10</td><td>指标管控模块。电子归档模块，系统整体优化。用林用草模块功能。一体化迁移</td><td>运维支持</td><td></td></tr><tr><td>11</td><td>初验文档编写。用林用草模块完善。一体化迁移</td><td>运维支持</td><td></td></tr><tr><td>12</td><td>智能体开发，系统全面优化，一体化迁移</td><td>运维支持</td><td></td></tr></tbody></table>',29),i=[h];function n(c,s){return d(),a("div",null,i)}const _=t(e,[["render",n],["__file","zhoubao.html.vue"]]);export{_ as default};
